function startQuiz(){resetState();UI.result.classList.add("hidden");UI.recommendations.innerHTML="";UI.realShifts.innerHTML="";UI.familyFit.innerHTML="";UI.fallbackBox.innerHTML="";UI.fallbackBox.classList.add("hidden");UI.quiz.classList.remove("hidden");closeLocationEditor();UI.quiz.scrollIntoView({behavior:"smooth",block:"start"});render();}
function resetState(){STATE.i=0;STATE.answers={};STATE.selected=[];STATE.badges=[];STATE.citySource=null;STATE.lastRecommendations=[];STATE.score={physical:50,communication:50,digital:50,stability:50,learning:50};UI.textAnswer.value="";UI.resultCityInput.value="";UI.resultMetroInput.value="";UI.metroSummary.textContent="";UI.metroSummary.classList.add("hidden");hideAutocomplete(UI.cityAutocomplete);hideAutocomplete(UI.resultCityAutocomplete);UI.inputWrap.classList.add("hidden");UI.multiActions.classList.add("hidden");UI.voiceControls.classList.add("hidden");UI.skipTextBtn.classList.add("hidden");stopVoiceInput();}
function render(){const[id,text,hint,type,options]=QUESTIONS[STATE.i];STATE.selected=Array.isArray(STATE.answers[id])?[...STATE.answers[id]]:[];UI.title.textContent=text;UI.hint.textContent=hint;UI.progressText.textContent=`${STATE.i+1}/${QUESTIONS.length}`;UI.progressBar.style.width=`${((STATE.i+1)/QUESTIONS.length)*100}%`;UI.badges.innerHTML=STATE.badges.map(x=>`<span class="badge">${escapeHtml(x)}</span>`).join("");UI.options.innerHTML="";UI.inputWrap.classList.add("hidden");UI.multiActions.classList.add("hidden");UI.voiceControls.classList.add("hidden");UI.skipTextBtn.classList.add("hidden");ACTIVE_CITY_INPUT=null;if(type==="single"){options.forEach(o=>UI.options.appendChild(makeOption(o,()=>answerSingle(id,o))));return;}if(type==="multi"){options.forEach(o=>{const button=makeOption(o,()=>toggleMulti(o));if(STATE.selected.includes(o))button.classList.add("selected");UI.options.appendChild(button);});UI.multiActions.classList.remove("hidden");return;}UI.inputWrap.classList.remove("hidden");UI.textAnswer.placeholder=getTextPlaceholder(id);UI.textAnswer.value=STATE.answers[id]||"";if(id==="city")ACTIVE_CITY_INPUT=UI.textAnswer;if(type==="text_optional"||type==="text_voice_optional")UI.skipTextBtn.classList.remove("hidden");configureVoiceControls(id);handleCityInput(UI.textAnswer,UI.cityAutocomplete);setTimeout(()=>UI.textAnswer.focus(),30);}
function makeOption(text,handler){const button=document.createElement("button");button.type="button";button.className="option";button.textContent=text;button.addEventListener("click",handler);return button;}
function toggleMulti(option){const isSelected=STATE.selected.includes(option);if(isSelected)STATE.selected=STATE.selected.filter(item=>item!==option);else if(STATE.selected.length<4)STATE.selected.push(option);[...UI.options.querySelectorAll(".option")].forEach(node=>node.classList.toggle("selected",STATE.selected.includes(node.textContent)));}
function answerSingle(id,answer){STATE.answers[id]=answer;adaptScore(id,answer);grantBadge(id,answer);next();}
function submitMulti(){const[id]=QUESTIONS[STATE.i];if(!STATE.selected.length)return;STATE.answers[id]=[...STATE.selected];adaptScore(id,STATE.selected);grantBadge(id,STATE.selected);next();}
function submitText(){const[id,,,type]=QUESTIONS[STATE.i];const value=UI.textAnswer.value.trim();if(!value&&type==="text")return;if(id==="city"){const meta=resolveCityMeta(value);if(!meta){handleCityInput(UI.textAnswer,UI.cityAutocomplete,true);return;}STATE.answers.city=meta.label;STATE.citySource=meta;}else{STATE.answers[id]=value;}if(id==="metro")STATE.answers.metro=value;if(id==="experience_details"){adaptScore(id,value);grantBadge(id,value);}next();}
function skipTextQuestion(){const[id]=QUESTIONS[STATE.i];STATE.answers[id]="";if(id==="metro")STATE.answers.metro="";next();}
function next(){const currentId=QUESTIONS[STATE.i][0];if(currentId==="city"){const meta=STATE.citySource||resolveCityMeta(STATE.answers.city||"");const nextQuestion=QUESTIONS[STATE.i+1];if(nextQuestion&&nextQuestion[0]==="metro"&&meta&&!meta.supportsMetro){STATE.answers.metro="";STATE.i+=2;render();return;}}STATE.i+=1;if(STATE.i>=QUESTIONS.length){finishQuiz();return;}render();}
function finishQuiz(){UI.quiz.classList.add("hidden");UI.result.classList.remove("hidden");const recommendations=computeRecommendations();STATE.lastRecommendations=recommendations;renderProfile(recommendations);renderRecommendations(recommendations.slice(0,3));renderFamilyFit(recommendations);renderRealShifts(recommendations.slice(0,3));drawRadar();UI.result.scrollIntoView({behavior:"smooth",block:"start"});}
function computeRecommendations(){const scored=ROLES.map(role=>({...role,score:scoreRole(role)})).sort((a,b)=>b.score-a.score);enforceCleaningRule(scored);return scored;}
function scoreRole(role){let score=52;const addMatch=(answerKey,goodAnswers,points,missPenalty=0)=>{const answer=STATE.answers[answerKey];if(!answer)return;if(Array.isArray(answer)){const matches=answer.filter(item=>goodAnswers.includes(item)).length;score+=matches*points;if(!matches)score-=missPenalty;return;}if(goodAnswers.includes(answer))score+=points;else score-=missPenalty;};addMatch("physical",role.fit.physical||[],10,8);addMatch("communication",role.fit.communication||[],11,9);addMatch("digital",role.fit.digital||[],9,7);addMatch("pay_model",role.fit.pay_model||[],8,6);addMatch("outdoor",role.fit.outdoor||[],8,8);addMatch("skills",role.boosts.skills||[],12,0);addMatch("interests",role.boosts.interests||[],10,0);if(STATE.answers.heavy_weight==="\\u041b\\u0443\\u0447\\u0448\\u0435 \\u0431\\u0435\\u0437 \\u0442\\u044f\\u0436\\u0435\\u043b\\u043e\\u0433\\u043e \\u0432\\u0435\\u0441\\u0430"&&["warehouse","cleaner_outdoor","courier","collector"].includes(role.code))score-=12;if(STATE.answers.standing==="\\u041d\\u0443\\u0436\\u043d\\u0430 \\u0441\\u0438\\u0434\\u044f\\u0447\\u0430\\u044f"&&["cashier","retail_floor","barista","courier","collector"].includes(role.code))score-=12;if(STATE.answers.pay_priority==="\\u0421\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u044b\\u0439 \\u043f\\u0440\\u043e\\u0433\\u043d\\u043e\\u0437\\u0438\\u0440\\u0443\\u0435\\u043c\\u044b\\u0439 \\u0434\\u043e\\u0445\\u043e\\u0434"&&["cashier","retail_floor","kitchen"].includes(role.code))score+=8;if(STATE.answers.pay_priority==="\\u041c\\u0430\\u043a\\u0441\\u0438\\u043c\\u0443\\u043c \\u0437\\u0430\\u0440\\u0430\\u0431\\u043e\\u0442\\u043a\\u0430"&&["courier","warehouse","collector"].includes(role.code))score+=8;if(STATE.answers.pay_priority==="\\u041a\\u043e\\u043c\\u0444\\u043e\\u0440\\u0442 \\u0438 \\u043c\\u0435\\u043d\\u044c\\u0448\\u0435 \\u0441\\u0442\\u0440\\u0435\\u0441\\u0441\\u0430"&&["retail_floor","cleaner_indoor","promoter"].includes(role.code))score+=6;if(STATE.answers.training_ready==="\\u0414\\u0430, \\u0435\\u0441\\u043b\\u0438 \\u044d\\u0442\\u043e \\u0434\\u0430\\u0441\\u0442 \\u0431\\u043e\\u043b\\u044c\\u0448\\u0435 \\u0432\\u043e\\u0437\\u043c\\u043e\\u0436\\u043d\\u043e\\u0441\\u0442\\u0435\\u0439"&&["barista","cashier","kitchen"].includes(role.code))score+=5;if((STATE.answers.experience_details||"").trim().length>40)score+=["kitchen","cashier","barista"].includes(role.code)?4:2;if(STATE.answers.age_group==="55+"&&["promoter","courier","cleaner_outdoor"].includes(role.code))score-=4;if(role.code.startsWith("cleaner"))score-=8;return clamp(Math.round(score),18,100);}
function enforceCleaningRule(items){items.sort((a,b)=>{const aCleaning=a.tags.includes("cleaner");const bCleaning=b.tags.includes("cleaner");if(aCleaning!==bCleaning)return aCleaning?1:-1;return b.score-a.score;});const top1=items.find(item=>!item.tags.includes("cleaner"));if(!top1)return;items.forEach(item=>{if(item.tags.includes("cleaner"))item.score=Math.min(item.score,Math.max(25,top1.score-1));});items.sort((a,b)=>b.score-a.score);}
function renderProfile(recommendations){const top=recommendations[0];UI.profileName.textContent=buildProfileName(top);UI.profileDesc.textContent=buildProfileDescription(top);UI.incomeForecast.textContent=`${formatMoney(top.pay*4)} \\u20bd`;UI.trainReadiness.textContent=mapTrainingReadiness();UI.topScore.textContent=`${top.score}%`;if(STATE.answers.metro){UI.metroSummary.textContent=`\\u0418\\u0449\\u0435\\u043c \\u0441\\u043c\\u0435\\u043d\\u044b \\u0440\\u044f\\u0434\\u043e\\u043c \\u0441 \\u043c\\u0435\\u0442\\u0440\\u043e: ${STATE.answers.metro}`;UI.metroSummary.classList.remove("hidden");}else{UI.metroSummary.classList.add("hidden");UI.metroSummary.textContent="";}}
function buildProfileName(top){if(top.code==="kitchen")return"\\u0422\\u044b - \\u043c\\u0430\\u0441\\u0442\\u0435\\u0440 \\u0441\\u043f\\u043e\\u043a\\u043e\\u0439\\u043d\\u043e\\u0433\\u043e \\u0442\\u0435\\u043c\\u043f\\u0430";if(top.code==="courier")return"\\u0422\\u044b - \\u043e\\u0445\\u043e\\u0442\\u043d\\u0438\\u043a \\u0437\\u0430 \\u0434\\u0432\\u0438\\u0436\\u0435\\u043d\\u0438\\u0435\\u043c \\u0438 \\u0434\\u043e\\u0445\\u043e\\u0434\\u043e\\u043c";if(top.code==="cashier")return"\\u0422\\u044b - \\u0443\\u0432\\u0435\\u0440\\u0435\\u043d\\u043d\\u044b\\u0439 \\u0444\\u0440\\u043e\\u043d\\u0442-\\u043b\\u0438\\u043d\\u0435\\u0439\\u043d\\u044b\\u0439 \\u043f\\u0440\\u043e\\u0444\\u0438";if(top.code==="collector")return"\\u0422\\u044b - \\u0441\\u0438\\u0441\\u0442\\u0435\\u043c\\u043d\\u044b\\u0439 \\u0441\\u0431\\u043e\\u0440\\u0449\\u0438\\u043a \\u0441 \\u0447\\u0443\\u0432\\u0441\\u0442\\u0432\\u043e\\u043c \\u0440\\u0438\\u0442\\u043c\\u0430";return`\\u0422\\u044b - ${top.family.toLowerCase()}-\\u043f\\u0440\\u043e\\u0444\\u0438\\u043b\\u044c \\u0441 \\u0445\\u043e\\u0440\\u043e\\u0448\\u0438\\u043c \\u043f\\u043e\\u0442\\u0435\\u043d\\u0446\\u0438\\u0430\\u043b\\u043e\\u043c`;}
function buildProfileDescription(top){const city=STATE.answers.city||"\\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435";return`\\u0421\\u0443\\u0434\\u044f \\u043f\\u043e \\u043e\\u0442\\u0432\\u0435\\u0442\\u0430\\u043c, \\u0442\\u0435\\u0431\\u0435 \\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u044f\\u0442 \\u0440\\u043e\\u043b\\u0438 \\u0441\\u0435\\u043c\\u0435\\u0439\\u0441\\u0442\\u0432\\u0430 \\u00ab${top.family}\\u00bb: \\u043f\\u043e \\u0443\\u0440\\u043e\\u0432\\u043d\\u044e \\u043d\\u0430\\u0433\\u0440\\u0443\\u0437\\u043a\\u0438, \\u0444\\u043e\\u0440\\u043c\\u0430\\u0442\\u0443 \\u043e\\u043f\\u043b\\u0430\\u0442\\u044b \\u0438 \\u0442\\u0435\\u043c\\u043f\\u0443 \\u0432\\u0445\\u043e\\u0434\\u0430. \\u0412 ${city} \\u0441\\u0442\\u043e\\u0438\\u0442 \\u043d\\u0430\\u0447\\u0430\\u0442\\u044c \\u0438\\u043c\\u0435\\u043d\\u043d\\u043e \\u0441 \\u044d\\u0442\\u043e\\u0433\\u043e \\u043d\\u0430\\u043f\\u0440\\u0430\\u0432\\u043b\\u0435\\u043d\\u0438\\u044f, \\u0430 \\u0434\\u0430\\u043b\\u044c\\u0448\\u0435 \\u0443\\u0436\\u0435 \\u0440\\u0430\\u0441\\u0448\\u0438\\u0440\\u044f\\u0442\\u044c \\u043d\\u0430\\u0431\\u043e\\u0440 \\u0440\\u043e\\u043b\\u0435\\u0439 \\u043f\\u043e \\u043c\\u0435\\u0440\\u0435 \\u043e\\u043f\\u044b\\u0442\\u0430.`;}
function mapTrainingReadiness(){const answer=STATE.answers.training_ready;if(answer==="\\u0414\\u0430, \\u0435\\u0441\\u043b\\u0438 \\u044d\\u0442\\u043e \\u0434\\u0430\\u0441\\u0442 \\u0431\\u043e\\u043b\\u044c\\u0448\\u0435 \\u0432\\u043e\\u0437\\u043c\\u043e\\u0436\\u043d\\u043e\\u0441\\u0442\\u0435\\u0439")return"\\u0412\\u044b\\u0441\\u043e\\u043a\\u0430\\u044f";if(answer==="\\u0422\\u043e\\u043b\\u044c\\u043a\\u043e \\u0435\\u0441\\u043b\\u0438 \\u043e\\u0431\\u0443\\u0447\\u0435\\u043d\\u0438\\u0435 \\u043a\\u043e\\u0440\\u043e\\u0442\\u043a\\u043e\\u0435")return"\\u0421\\u0440\\u0435\\u0434\\u043d\\u044f\\u044f";return"\\u041d\\u0438\\u0437\\u043a\\u0430\\u044f";}
function renderRecommendations(recommendations){UI.recommendations.innerHTML=`<h3>\\u0422\\u043e\\u043f-3 \\u043f\\u0440\\u043e\\u0444\\u0435\\u0441\\u0441\\u0438\\u0438 \\u0434\\u043b\\u044f \\u0442\\u0435\\u0431\\u044f</h3>${recommendations.map(renderRoleCard).join("")}`;}
function renderRoleCard(role){return`<div class="rec-card"><h4>${escapeHtml(role.role)} - match ${role.score}%</h4><p><strong>\\u0421\\u0435\\u043c\\u0435\\u0439\\u0441\\u0442\\u0432\\u043e:</strong> ${escapeHtml(role.family)} | <strong>\\u041e\\u0440\\u0438\\u0435\\u043d\\u0442\\u0438\\u0440 \\u043f\\u043e \\u0441\\u0442\\u0430\\u0432\\u043a\\u0435:</strong> ${formatMoney(role.pay)} \\u20bd \\u0437\\u0430 \\u0441\\u043c\\u0435\\u043d\\u0443</p><div>${role.tags.map(tag=>`<span class="tag">${escapeHtml(tag)}</span>`).join("")}</div></div>`;}
function renderFamilyFit(recommendations){const families=new Map();recommendations.forEach(role=>{if(!families.has(role.family))families.set(role.family,[]);families.get(role.family).push(role.score);});const rows=Array.from(families.entries()).map(([family,values])=>{const avg=values.reduce((sum,value)=>sum+value,0)/values.length;const max=Math.max(...values);const score=clamp(Math.round(avg*0.65+max*0.35),18,100);return{family,score};}).sort((a,b)=>b.score-a.score);UI.familyFit.innerHTML=`<h3>\\u041a\\u0430\\u0442\\u0430\\u043b\\u043e\\u0433 \\u043f\\u0440\\u043e\\u0444\\u0435\\u0441\\u0441\\u0438\\u0439 \\u0421\\u043c\\u0435\\u043d\\u044b: \\u0442\\u0432\\u043e\\u0439 \\u0443\\u0440\\u043e\\u0432\\u0435\\u043d\\u044c \\u0441\\u043e\\u0432\\u043f\\u0430\\u0434\\u0435\\u043d\\u0438\\u044f</h3>${rows.map(item=>`<div class="rec-card"><p><strong>${escapeHtml(item.family)}</strong> - ${item.score}%</p><div class="progress"><span style="width:${item.score}%"></span></div></div>`).join("")}`;}
async function renderRealShifts(topRoles){const city=STATE.answers.city||"";const metro=STATE.answers.metro||"";if(!city){UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">\\u0421\\u043d\\u0430\\u0447\\u0430\\u043b\\u0430 \\u0443\\u043a\\u0430\\u0436\\u0438 \\u0433\\u043e\\u0440\\u043e\\u0434, \\u0447\\u0442\\u043e\\u0431\\u044b \\u043c\\u044b \\u043c\\u043e\\u0433\\u043b\\u0438 \\u043f\\u043e\\u0434\\u043e\\u0431\\u0440\\u0430\\u0442\\u044c \\u043f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b.</p>`;return;}UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">\\u0418\\u0449\\u0435\\u043c \\u0441\\u0430\\u043c\\u044b\\u0435 \\u0431\\u043b\\u0438\\u0437\\u043a\\u0438\\u0435 \\u043a \\u043f\\u0440\\u043e\\u0444\\u0438\\u043b\\u044e \\u0441\\u043c\\u0435\\u043d\\u044b...</p>`;try{const dates=upcomingDates(2).join(",");const response=await fetch(`/api/shifts?city=${encodeURIComponent(city)}&dates=${encodeURIComponent(dates)}`);const data=await response.json();if(!response.ok){UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">${escapeHtml(data.message||"\\u041d\\u0435 \\u0443\\u0434\\u0430\\u043b\\u043e\\u0441\\u044c \\u043f\\u043e\\u043b\\u0443\\u0447\\u0438\\u0442\\u044c \\u043f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b.")}</p>`;return;}const ranked=(data.shifts||[]).map(shift=>({...shift,fitScore:scoreShift(shift,topRoles,metro)})).sort((a,b)=>b.fitScore-a.fitScore).slice(0,3);if(!ranked.length){const note=data.extendedRange?`\\u041d\\u0430 \\u0437\\u0430\\u0432\\u0442\\u0440\\u0430 \\u0438 \\u043f\\u043e\\u0441\\u043b\\u0435\\u0437\\u0430\\u0432\\u0442\\u0440\\u0430 \\u0441\\u043c\\u0435\\u043d \\u043d\\u0435 \\u043d\\u0430\\u0448\\u043b\\u043e\\u0441\\u044c, \\u043f\\u043e\\u044d\\u0442\\u043e\\u043c\\u0443 \\u043c\\u044b \\u043f\\u043e\\u0441\\u043c\\u043e\\u0442\\u0440\\u0435\\u043b\\u0438 \\u0447\\u0443\\u0442\\u044c \\u0434\\u0430\\u043b\\u044c\\u0448\\u0435 \\u043f\\u043e \\u0434\\u0430\\u0442\\u0430\\u043c \\u0434\\u043b\\u044f \\u0433\\u043e\\u0440\\u043e\\u0434\\u0430 ${escapeHtml(data.cityLabel||city)}.`:`\\u041f\\u043e\\u043a\\u0430 \\u0432 \\u043f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u043e\\u0439 \\u0432\\u0438\\u0442\\u0440\\u0438\\u043d\\u0435 \\u043d\\u0435 \\u0432\\u0438\\u0434\\u043d\\u043e \\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u044f\\u0449\\u0438\\u0445 \\u0441\\u043c\\u0435\\u043d \\u0434\\u043b\\u044f \\u0433\\u043e\\u0440\\u043e\\u0434\\u0430 ${escapeHtml(data.cityLabel||city)} \\u043d\\u0430 \\u0431\\u043b\\u0438\\u0436\\u0430\\u0439\\u0448\\u0438\\u0435 \\u0434\\u0430\\u0442\\u044b.`;UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">${note}</p>`;return;}const intro=data.extendedRange?`\\u041d\\u0430 \\u0431\\u043b\\u0438\\u0436\\u0430\\u0439\\u0448\\u0438\\u0435 2 \\u0434\\u043d\\u044f \\u0432\\u0438\\u0442\\u0440\\u0438\\u043d\\u0430 \\u0431\\u044b\\u043b\\u0430 \\u043f\\u0443\\u0441\\u0442\\u043e\\u0439, \\u043f\\u043e\\u044d\\u0442\\u043e\\u043c\\u0443 \\u043c\\u044b \\u043f\\u043e\\u043a\\u0430\\u0437\\u0430\\u043b\\u0438 \\u043b\\u0443\\u0447\\u0448\\u0438\\u0435 \\u0434\\u043e\\u0441\\u0442\\u0443\\u043f\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0438\\u0437 \\u0440\\u0430\\u0441\\u0448\\u0438\\u0440\\u0435\\u043d\\u043d\\u043e\\u0433\\u043e \\u0434\\u0438\\u0430\\u043f\\u0430\\u0437\\u043e\\u043d\\u0430 \\u0434\\u043b\\u044f ${escapeHtml(data.cityLabel||city)}.`:`\\u041f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u0430\\u044f \\u0432\\u0438\\u0442\\u0440\\u0438\\u043d\\u0430 \\u0421\\u043c\\u0435\\u043d\\u044b \\u043d\\u0430 ${escapeHtml(data.cityLabel||city)}. \\u041d\\u0438\\u0436\\u0435 2-3 \\u0441\\u0430\\u043c\\u044b\\u0435 \\u0431\\u043b\\u0438\\u0437\\u043a\\u0438\\u0435 \\u043f\\u043e \\u043f\\u0440\\u043e\\u0444\\u0438\\u043b\\u044e \\u0441\\u043c\\u0435\\u043d\\u044b.`;UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">${intro}</p>${ranked.map(renderShiftCard).join("")}`;}catch{UI.realShifts.innerHTML=`<h3>\\u0420\\u0435\\u0430\\u043b\\u044c\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0432 \\u0442\\u0432\\u043e\\u0435\\u043c \\u0433\\u043e\\u0440\\u043e\\u0434\\u0435</h3><p class="muted">\\u041d\\u0435 \\u0443\\u0434\\u0430\\u043b\\u043e\\u0441\\u044c \\u0437\\u0430\\u0433\\u0440\\u0443\\u0437\\u0438\\u0442\\u044c \\u043f\\u0443\\u0431\\u043b\\u0438\\u0447\\u043d\\u044b\\u0435 \\u0441\\u043c\\u0435\\u043d\\u044b \\u0441 \\u0432\\u0438\\u0442\\u0440\\u0438\\u043d\\u044b.</p>`;}}
function buildShiftLocationText(shift){return[shift.address||"",shift.station||"",shift.landmark||""].join(" ").trim();}function scoreShift(shift,topRoles,metro){const title=normalize(shift.title);const location=normalize(buildShiftLocationText(shift));let score=50;topRoles.forEach((role,index)=>{const weight=12-index*3;if(title.includes(normalize(role.family))||title.includes(normalize(role.role)))score+=weight;if((role.boosts.skills||[]).some(item=>title.includes(normalize(item))))score+=weight+2;});if(metro){metro.split(",").map(item=>normalize(item)).filter(Boolean).forEach(item=>{if(location.includes(item))score+=8;});}return clamp(Math.round(score),30,100);}
function renderShiftCard(shift){const linkLabel=shift.isDirectUrl?"\\u041f\\u0440\\u044f\\u043c\\u0430\\u044f \\u0441\\u0441\\u044b\\u043b\\u043a\\u0430":"\\u0421\\u0441\\u044b\\u043b\\u043a\\u0430 \\u043d\\u0430 \\u0441\\u043f\\u0438\\u0441\\u043e\\u043a \\u0441\\u043c\\u0435\\u043d";const ctaLabel=shift.isDirectUrl?"\\u041e\\u0442\\u043a\\u0440\\u044b\\u0442\\u044c \\u0441\\u043c\\u0435\\u043d\\u0443":"\\u041e\\u0442\\u043a\\u0440\\u044b\\u0442\\u044c \\u0441\\u043f\\u0438\\u0441\\u043e\\u043a \\u0441\\u043c\\u0435\\u043d \\u043d\\u0430 \\u044d\\u0442\\u0443 \\u0434\\u0430\\u0442\\u0443";const href=shift.isDirectUrl?shift.url:shift.listUrl;const reason=explainShiftFit(shift);const whereLine=shift.address||shift.landmark||"\\u0410\\u0434\\u0440\\u0435\\u0441 \\u0443\\u0442\\u043e\\u0447\\u043d\\u044f\\u0435\\u0442\\u0441\\u044f";const stationLine=shift.station?`<p><strong>\\u041c\\u0435\\u0442\\u0440\\u043e:</strong> ${escapeHtml(shift.station)}</p>`:"";const landmarkLine=shift.landmark&&shift.landmark!==whereLine?`<p><strong>\\u041e\\u0440\\u0438\\u0435\\u043d\\u0442\\u0438\\u0440:</strong> ${escapeHtml(shift.landmark)}</p>`:"";return`<div class="rec-card"><h4>${escapeHtml(shift.title)} - fit ${shift.fitScore}%</h4><a class="shift-pill-link" href="${escapeHtmlAttr(href)}" target="_blank" rel="noopener noreferrer"><span class="tag ${shift.isDirectUrl?"tag-direct":"tag-list"}">${linkLabel}</span></a><p><strong>\\u041a\\u043e\\u0433\\u0434\\u0430:</strong> ${escapeHtml(shift.dateLabel||shift.date||"")}${shift.time?`, ${escapeHtml(shift.time)}`:""}</p><p><strong>\\u0413\\u0434\\u0435:</strong> ${escapeHtml(whereLine)}</p>${stationLine}${landmarkLine}<p><strong>\\u041e\\u043f\\u043b\\u0430\\u0442\\u0430:</strong> ${escapeHtml(shift.payText||"\\u0421\\u0442\\u0430\\u0432\\u043a\\u0430 \\u0443\\u0442\\u043e\\u0447\\u043d\\u044f\\u0435\\u0442\\u0441\\u044f")}</p><p class="muted">${escapeHtml(reason)}</p><a class="shift-link shift-cta" href="${escapeHtmlAttr(href)}" target="_blank" rel="noopener noreferrer">${ctaLabel}</a></div>`;}
function explainShiftFit(shift){const reasons=[];const title=normalize(shift.title);const targetMetro=normalize(STATE.answers.metro.split(",")[0]||"");const location=normalize(buildShiftLocationText(shift));if(targetMetro&&location.includes(targetMetro))reasons.push("\\u0441\\u043e\\u0432\\u043f\\u0430\\u0434\\u0430\\u0435\\u0442 \\u043f\\u043e \\u043c\\u0435\\u0442\\u0440\\u043e");if(title.includes("\\u043a\\u0443\\u0445"))reasons.push("\\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u0438\\u0442 \\u043f\\u043e \\u043a\\u0443\\u0445\\u043d\\u0435");if(title.includes("\\u043a\\u0430\\u0441\\u0441"))reasons.push("\\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u0438\\u0442 \\u043f\\u043e \\u0444\\u043e\\u0440\\u043c\\u0430\\u0442\\u0443 \\u043e\\u0431\\u0449\\u0435\\u043d\\u0438\\u044f");if(title.includes("\\u0441\\u0431\\u043e\\u0440")||title.includes("\\u0434\\u0430\\u0440\\u043a\\u0441\\u0442"))reasons.push("\\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u0438\\u0442 \\u043f\\u043e \\u0442\\u0435\\u043c\\u043f\\u0443 \\u0438 \\u0441\\u0431\\u043e\\u0440\\u043a\\u0435");if(title.includes("\\u043a\\u0443\\u0440\\u044c\\u0435\\u0440"))reasons.push("\\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u0438\\u0442 \\u043f\\u043e \\u0444\\u043e\\u0440\\u043c\\u0430\\u0442\\u0443 \\u043e\\u043f\\u043b\\u0430\\u0442\\u044b \\u0438 \\u0434\\u0432\\u0438\\u0436\\u0435\\u043d\\u0438\\u044e");if(!reasons.length)reasons.push("\\u0441\\u043e\\u0432\\u043f\\u0430\\u0434\\u0430\\u0435\\u0442 \\u043f\\u043e \\u043e\\u0431\\u0449\\u0435\\u043c\\u0443 \\u043f\\u0440\\u043e\\u0444\\u0438\\u043b\\u044e");return`\\u041f\\u043e\\u0447\\u0435\\u043c\\u0443 \\u044d\\u0442\\u043e \\u0442\\u0435\\u0431\\u0435 \\u043f\\u043e\\u0434\\u0445\\u043e\\u0434\\u0438\\u0442: ${reasons.join(", ")}.`;}
function downloadProfile(){const recommendations=STATE.lastRecommendations.length?STATE.lastRecommendations:computeRecommendations();const payload={generatedAt:new Date().toISOString(),city:STATE.answers.city||"",metro:STATE.answers.metro||"",answers:STATE.answers,experience:{details:String(STATE.answers.experience_details||"").trim(),hasDetails:Boolean(String(STATE.answers.experience_details||"").trim())},recommendations:recommendations.slice(0,5).map(item=>({code:item.code,role:item.role,family:item.family,score:item.score,pay:item.pay}))};const blob=new Blob([JSON.stringify(payload,null,2)],{type:"application/json;charset=utf-8"});const url=URL.createObjectURL(blob);const link=document.createElement("a");link.href=url;link.download="smena-profile.json";link.click();URL.revokeObjectURL(url);}
async function loadCitiesConfig(){try{const response=await fetch("/api/cities");const data=await response.json();if(response.ok&&Array.isArray(data.cities)&&data.cities.length){const support={};CITY_OPTIONS=data.cities.map(item=>decodeClientText(item.label)).filter(Boolean);data.cities.forEach(item=>{const label=decodeClientText(item.label);const aliases=(Array.isArray(item.aliases)&&item.aliases.length?item.aliases:[item.label]).map(alias=>decodeClientText(alias)).filter(Boolean);aliases.forEach(alias=>{support[normalize(alias)]={id:item.id,slug:item.slug,label,supportsMetro:Boolean(item.supportsMetro),aliases};});});CITY_SUPPORT=support;CITIES_LOADED=true;return;}}catch{}CITY_OPTIONS=[];CITY_SUPPORT={};CITIES_LOADED=false;}
function handleCityInput(input,container,forceOpen=false){if(!container||(input!==ACTIVE_CITY_INPUT&&input!==UI.resultCityInput))return;const value=input.value.trim();const options=getCityMatches(value);if(!value&&!forceOpen){hideAutocomplete(container);return;}if(!CITIES_LOADED){container.innerHTML=`<div class="autocomplete-empty">\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd \\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd \\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd...</div>`;container.classList.remove("hidden");return;}if(!options.length){container.innerHTML=`<div class="autocomplete-empty">\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd \\ufffd\\ufffd \\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd \\ufffd \\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd \\ufffd\\ufffd\\ufffd\\ufffd\\ufffd\\ufffd</div>`;container.classList.remove("hidden");return;}container.innerHTML=options.map(label=>`<button type="button" class="autocomplete-item">${escapeHtml(label)}</button>`).join("");container.classList.remove("hidden");[...container.querySelectorAll(".autocomplete-item")].forEach(node=>{node.addEventListener("click",()=>{input.value=node.textContent;if(input===UI.textAnswer){STATE.answers.city=node.textContent;STATE.citySource=resolveCityMeta(node.textContent);}if(input===UI.resultCityInput)syncLocationEditorState();hideAutocomplete(container);});});}
function getCityMatches(value){const normalized=normalize(value);if(!normalized)return CITY_OPTIONS.slice(0,8);return CITY_OPTIONS.filter(city=>normalize(city).includes(normalized)).slice(0,8);}function hideAutocomplete(node){node.classList.add("hidden");node.innerHTML="";}function handleOutsideAutocompleteClick(event){if(!event.target.closest(".suggest-input")){hideAutocomplete(UI.cityAutocomplete);hideAutocomplete(UI.resultCityAutocomplete);}}
function resolveCityMeta(input){const key=normalize(input);if(!key)return null;return CITY_SUPPORT[key]||Object.entries(CITY_SUPPORT).find(([alias])=>alias.includes(key)||key.includes(alias))?.[1]||null;}function decodeClientText(value){let text=String(value||"");for(let i=0;i<2;i+=1){if(!/[\\ufffd\\u0441]/.test(text))break;try{const bytes=Uint8Array.from(Array.from(text).map(ch=>ch.charCodeAt(0)&255));const decoded=new TextDecoder("utf-8").decode(bytes);if(decoded&&decoded!==text)text=decoded;}catch{break;}}return text;}
function normalize(value){return String(value||"").toLowerCase().replace(/\\u0451/g,"\\u0435").replace(/^\\u0433\.\s*/g,"").replace(/^\\u0433\\u043e\\u0440\\u043e\\u0434\s+/g,"").replace(/[.,]/g," ").replace(/\s+/g," ").trim();}
function adaptScore(id,answer){const add=(key,delta)=>STATE.score[key]=clamp(STATE.score[key]+delta,10,100);if(id==="physical")add("physical",answer==="\\u0422\\u044f\\u0436\\u0435\\u043b\\u0430\\u044f"?20:answer==="\\u0421\\u0440\\u0435\\u0434\\u043d\\u044f\\u044f"?8:-8);if(id==="communication")add("communication",answer==="\\u041b\\u044e\\u0431\\u043b\\u044e \\u043e\\u0431\\u0449\\u0430\\u0442\\u044c\\u0441\\u044f"?20:answer==="\\u041d\\u043e\\u0440\\u043c\\u0430\\u043b\\u044c\\u043d\\u043e"?5:-14);if(id==="digital")add("digital",answer==="\\u0423\\u0432\\u0435\\u0440\\u0435\\u043d\\u043d\\u043e"?20:answer==="\\u041d\\u043e\\u0440\\u043c\\u0430\\u043b\\u044c\\u043d\\u043e"?6:-14);if(id==="pay_priority")add("stability",answer==="\\u0421\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u044b\\u0439 \\u043f\\u0440\\u043e\\u0433\\u043d\\u043e\\u0437\\u0438\\u0440\\u0443\\u0435\\u043c\\u044b\\u0439 \\u0434\\u043e\\u0445\\u043e\\u0434"?18:answer==="\\u041a\\u043e\\u043c\\u0444\\u043e\\u0440\\u0442 \\u0438 \\u043c\\u0435\\u043d\\u044c\\u0448\\u0435 \\u0441\\u0442\\u0440\\u0435\\u0441\\u0441\\u0430"?8:-8);if(id==="training_ready")add("learning",answer==="\\u0414\\u0430, \\u0435\\u0441\\u043b\\u0438 \\u044d\\u0442\\u043e \\u0434\\u0430\\u0441\\u0442 \\u0431\\u043e\\u043b\\u044c\\u0448\\u0435 \\u0432\\u043e\\u0437\\u043c\\u043e\\u0436\\u043d\\u043e\\u0441\\u0442\\u0435\\u0439"?20:answer==="\\u0422\\u043e\\u043b\\u044c\\u043a\\u043e \\u0435\\u0441\\u043b\\u0438 \\u043e\\u0431\\u0443\\u0447\\u0435\\u043d\\u0438\\u0435 \\u043a\\u043e\\u0440\\u043e\\u0442\\u043a\\u043e\\u0435"?8:-10);}
function grantBadge(id,answer){const add=text=>{if(!STATE.badges.includes(text))STATE.badges.push(text);};if(id==="communication"&&answer==="\\u041b\\u044e\\u0431\\u043b\\u044e \\u043e\\u0431\\u0449\\u0430\\u0442\\u044c\\u0441\\u044f")add("\\u041b\\u044e\\u0431\\u0438\\u0442 \\u043e\\u0431\\u0449\\u0435\\u043d\\u0438\\u0435");if(id==="digital"&&answer==="\\u0423\\u0432\\u0435\\u0440\\u0435\\u043d\\u043d\\u043e")add("\\u0426\\u0438\\u0444\\u0440\\u043e\\u0432\\u043e\\u0439 \\u043f\\u0440\\u043e\\u0444\\u0438");if(id==="physical"&&answer==="\\u0422\\u044f\\u0436\\u0435\\u043b\\u0430\\u044f")add("\\u0413\\u043e\\u0442\\u043e\\u0432 \\u043a \\u0432\\u044b\\u0441\\u043e\\u043a\\u043e\\u0439 \\u043d\\u0430\\u0433\\u0440\\u0443\\u0437\\u043a\\u0435");if(id==="pay_priority"&&answer==="\\u0421\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u044b\\u0439 \\u043f\\u0440\\u043e\\u0433\\u043d\\u043e\\u0437\\u0438\\u0440\\u0443\\u0435\\u043c\\u044b\\u0439 \\u0434\\u043e\\u0445\\u043e\\u0434")add("\\u0426\\u0435\\u043d\\u0438\\u0442 \\u0441\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u043e\\u0441\\u0442\\u044c");if(id==="experience_details"&&String(answer||"").trim())add("\\u0415\\u0441\\u0442\\u044c \\u0440\\u0430\\u0441\\u0441\\u043a\\u0430\\u0437 \\u043e \\u0440\\u0435\\u043b\\u0435\\u0432\\u0430\\u043d\\u0442\\u043d\\u043e\\u043c \\u043e\\u043f\\u044b\\u0442\\u0435");}
function getTextPlaceholder(id){if(id==="city")return"\\u041d\\u0430\\u043f\\u0440\\u0438\\u043c\\u0435\\u0440: \\u041c\\u043e\\u0441\\u043a\\u0432\\u0430";if(id==="metro")return"\\u041d\\u0430\\u043f\\u0440\\u0438\\u043c\\u0435\\u0440: \\u0411\\u0435\\u043b\\u043e\\u0440\\u0443\\u0441\\u0441\\u043a\\u0430\\u044f, \\u0421\\u0430\\u0432\\u0435\\u043b\\u043e\\u0432\\u0441\\u043a\\u0430\\u044f";if(id==="experience_details")return"\\u041a\\u043e\\u0440\\u043e\\u0442\\u043a\\u043e \\u0440\\u0430\\u0441\\u0441\\u043a\\u0430\\u0436\\u0438\\u0442\\u0435, \\u0433\\u0434\\u0435 \\u0440\\u0430\\u0431\\u043e\\u0442\\u0430\\u043b\\u0438 \\u0438 \\u0447\\u0442\\u043e \\u0443\\u043c\\u0435\\u0435\\u0442\\u0435";return"\\u0412\\u0432\\u0435\\u0434\\u0438\\u0442\\u0435 \\u043e\\u0442\\u0432\\u0435\\u0442";}
function configureVoiceControls(questionId){if(questionId!=="experience_details"){UI.voiceControls.classList.add("hidden");stopVoiceInput();return;}const SpeechRecognition=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SpeechRecognition){UI.voiceControls.classList.add("hidden");return;}UI.voiceControls.classList.remove("hidden");}
function toggleVoiceInput(){const SpeechRecognition=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SpeechRecognition)return;if(speechActive){stopVoiceInput();return;}speechRecognition=new SpeechRecognition();speechRecognition.lang="ru-RU";speechRecognition.interimResults=true;speechRecognition.continuous=false;speechRecognition.onstart=()=>{speechActive=true;UI.voiceControls.classList.add("is-recording");UI.voiceStatus.textContent="\\u0421\\u043b\\u0443\\u0448\\u0430\\u044e...";UI.voiceBtn.textContent="\\u041e\\u0441\\u0442\\u0430\\u043d\\u043e\\u0432\\u0438\\u0442\\u044c \\u0437\\u0430\\u043f\\u0438\\u0441\\u044c";};speechRecognition.onresult=event=>{const transcript=Array.from(event.results).map(result=>result[0]?.transcript||"").join(" ").trim();UI.textAnswer.value=transcript;};speechRecognition.onerror=()=>{UI.voiceStatus.textContent="\\u041d\\u0435 \\u0443\\u0434\\u0430\\u043b\\u043e\\u0441\\u044c \\u0440\\u0430\\u0441\\u043f\\u043e\\u0437\\u043d\\u0430\\u0442\\u044c \\u0433\\u043e\\u043b\\u043e\\u0441\\u043e\\u0432\\u043e\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442";stopVoiceInput();};speechRecognition.onend=()=>{if(speechActive){speechActive=false;UI.voiceControls.classList.remove("is-recording");UI.voiceStatus.textContent="\\u041c\\u043e\\u0436\\u043d\\u043e \\u043d\\u0430\\u0434\\u0438\\u043a\\u0442\\u043e\\u0432\\u0430\\u0442\\u044c \\u043e\\u0442\\u0432\\u0435\\u0442 \\u0433\\u043e\\u043b\\u043e\\u0441\\u043e\\u043c";UI.voiceBtn.textContent="\\u0413\\u043e\\u043b\\u043e\\u0441\\u043e\\u0432\\u043e\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442";}};speechRecognition.start();}
function stopVoiceInput(){if(speechRecognition){try{speechRecognition.stop();}catch{}}speechActive=false;UI.voiceControls.classList.remove("is-recording");UI.voiceStatus.textContent="\\u041c\\u043e\\u0436\\u043d\\u043e \\u043d\\u0430\\u0434\\u0438\\u043a\\u0442\\u043e\\u0432\\u0430\\u0442\\u044c \\u043e\\u0442\\u0432\\u0435\\u0442 \\u0433\\u043e\\u043b\\u043e\\u0441\\u043e\\u043c";UI.voiceBtn.textContent="\\u0413\\u043e\\u043b\\u043e\\u0441\\u043e\\u0432\\u043e\\u0439 \\u043e\\u0442\\u0432\\u0435\\u0442";}
function openLocationEditor(){UI.locationEditor.classList.remove("hidden");UI.resultCityInput.value=STATE.answers.city||"";UI.resultMetroInput.value=STATE.answers.metro||"";syncLocationEditorState();}function closeLocationEditor(){UI.locationEditor.classList.add("hidden");hideAutocomplete(UI.resultCityAutocomplete);}function syncLocationEditorState(){const meta=resolveCityMeta(UI.resultCityInput.value);if(meta&&meta.supportsMetro){UI.resultMetroInput.disabled=false;UI.resultMetroHint.textContent="\\u041c\\u043e\\u0436\\u043d\\u043e \\u0443\\u043a\\u0430\\u0437\\u0430\\u0442\\u044c 1-3 \\u0441\\u0442\\u0430\\u043d\\u0446\\u0438\\u0438 \\u043c\\u0435\\u0442\\u0440\\u043e \\u0447\\u0435\\u0440\\u0435\\u0437 \\u0437\\u0430\\u043f\\u044f\\u0442\\u0443\\u044e.";}else{UI.resultMetroInput.value="";UI.resultMetroInput.disabled=true;UI.resultMetroHint.textContent="\\u0414\\u043b\\u044f \\u044d\\u0442\\u043e\\u0433\\u043e \\u0433\\u043e\\u0440\\u043e\\u0434\\u0430 \\u043c\\u0435\\u0442\\u0440\\u043e \\u043d\\u0435 \\u0438\\u0441\\u043f\\u043e\\u043b\\u044c\\u0437\\u0443\\u0435\\u0442\\u0441\\u044f.";}}
function applyLocationChanges(){const meta=resolveCityMeta(UI.resultCityInput.value);if(!meta)return;STATE.answers.city=meta.label;STATE.citySource=meta;STATE.answers.metro=meta.supportsMetro?UI.resultMetroInput.value.trim():"";closeLocationEditor();renderProfile(STATE.lastRecommendations);renderRealShifts(STATE.lastRecommendations.slice(0,3));}
function drawRadar(){const canvas=UI.radar;const ctx=canvas.getContext("2d");const width=canvas.width;const height=canvas.height;ctx.clearRect(0,0,width,height);const labels=[["\\u0424\\u0438\\u0437\\u043d\\u0430\\u0433\\u0440\\u0443\\u0437\\u043a\\u0430",STATE.score.physical],["\\u041e\\u0431\\u0449\\u0435\\u043d\\u0438\\u0435",STATE.score.communication],["\\u0426\\u0438\\u0444\\u0440\\u0430",STATE.score.digital],["\\u0421\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u043e\\u0441\\u0442\\u044c",STATE.score.stability],["\\u041e\\u0431\\u0443\\u0447\\u0435\\u043d\\u0438\\u0435",STATE.score.learning]];const cx=width/2;const cy=height/2;const radius=82;const angleStep=(Math.PI*2)/labels.length;ctx.strokeStyle="#dbe4ee";for(let ring=1;ring<=4;ring+=1){ctx.beginPath();labels.forEach((_,index)=>{const angle=-Math.PI/2+index*angleStep;const r=(radius/4)*ring;const x=cx+Math.cos(angle)*r;const y=cy+Math.sin(angle)*r;if(!index)ctx.moveTo(x,y);else ctx.lineTo(x,y);});ctx.closePath();ctx.stroke();}ctx.strokeStyle="#94a3b8";labels.forEach((label,index)=>{const angle=-Math.PI/2+index*angleStep;ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(cx+Math.cos(angle)*radius,cy+Math.sin(angle)*radius);ctx.stroke();const lx=cx+Math.cos(angle)*(radius+20);const ly=cy+Math.sin(angle)*(radius+20);ctx.fillStyle="#14213d";ctx.font="12px Segoe UI";ctx.textAlign="center";ctx.fillText(label[0],lx,ly);});ctx.beginPath();labels.forEach((label,index)=>{const angle=-Math.PI/2+index*angleStep;const r=radius*(label[1]/100);const x=cx+Math.cos(angle)*r;const y=cy+Math.sin(angle)*r;if(!index)ctx.moveTo(x,y);else ctx.lineTo(x,y);});ctx.closePath();ctx.fillStyle="rgba(15, 118, 110, 0.24)";ctx.strokeStyle="#0f766e";ctx.lineWidth=2;ctx.fill();ctx.stroke();}
function upcomingDates(days){const out=[];const today=new Date();for(let i=1;i<=days;i+=1){const date=new Date(today);date.setDate(today.getDate()+i);out.push(date.toISOString().slice(0,10));}return out;}function clamp(value,min,max){return Math.max(min,Math.min(max,value));}function formatMoney(value){return new Intl.NumberFormat("ru-RU").format(value);}function escapeHtml(value){return String(value||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/\"/g,"&quot;");}function escapeHtmlAttr(value){return escapeHtml(value).replace(/'/g,"&#39;");}

